package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.StringReader;

import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testIsNullStringSet_NullStringIsNull_ReturnsFalse() {
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n", null, null, false, false);

        boolean result = csvFormat.isNullStringSet();

        assertFalse(result);
    }

    @Test
    public void testIsNullStringSet_NullStringIsNotNull_ReturnsTrue() {
        CSVFormat csvFormat = new CSVFormat(',', '\"', null, null, null, false, true, "\r\n", "NULL", null, false, false);

        boolean result = csvFormat.isNullStringSet();

        assertTrue(result);
    }

